insert into codex_guidelines (id, data) values
  ('gl-daily', $relay${"id":"gl-daily","name":"Daily Report SOP","version":"v7","updated":"2026-06-22","updatedBy":"NW0005116","source":"Feature sync","summary":"Log the day in the Submit chat by 22:00 IST: pick Product-Audience, an Output Category (auto-derives Task/Activity/Metric), optional Stack, then the output count and the tailored template — every category now requires at least a written description. Finish with hours and status. Each task mirrors into a worklog instantly."}$relay$::jsonb),
  ('gl-weekly', $relay${"id":"gl-weekly","name":"Weekly Report Guidelines","version":"v5","updated":"2026-06-22","updatedBy":"NW0005116","source":"Feature sync","summary":"Rollup drafts the weekly from the week's daily reports into Highlights / Risks / Asks, each citing source report ids. Risks are always paired with an explicit Ask. Drafts are review-gated before publish; the Weekly Digest consolidates one achievement line per work-stream per sub-department."}$relay$::jsonb),
  ('gl-task', $relay${"id":"gl-task","name":"Task Format Guidelines","version":"v4","updated":"2026-06-22","updatedBy":"NW0002526","source":"Feature sync","summary":"Every task has an owner (managers pick from their reporting subtree — an L2 sees their L1s), a required Task details description, an Output Category, a required due date, and a status (In-progress/Done/Blocked/Overdue/Backlog) — no priority field. Optional Product-Audience, Stack and template fields. Only the owner changes status; Blocked arms the Sentry escalation chain."}$relay$::jsonb)
